mapper.select:
select * from pr_import_heat_temp
where company_id = #{companyId} and type = '0' and create_by = #{create}
  and (house_id is null or org_id is null) limit 500

select * from pr_import_heat_temp t inner join (
    select meter_num from pr_import_heat_temp
    where company_id = #{companyId} and type = '0' and create_by = #{create}
    group by meter_num having count(1) > 1
) dup on t.meter_num = dup.meter_num
where t.company_id = #{companyId} and t.type = '0' and t.create_by = #{create}
limit 500
